import asyncio
import uuid
import json
from websockets import serve, ConnectionClosed

# In-memory inventory system (replace with a database for persistence)
inventories = {}

class Player:
    def __init__(self, id):
        self.id = id
        self.inventory = []

async def handle_connection(websocket, path):
    player_id = str(uuid.uuid4())
    inventories[player_id] = []
    
    while True:
        try:
            message = await websocket.recv()
            data = json.loads(message)
            
            if data['type'] == 'add_item':
                item_id = data['item_id']
                quantity = data['quantity']
                
                # Prevent game item duplication
                if not any(item['id'] == item_id for item in inventories[player_id]):
                    inventories[player_id].append({'id': item_id, 'quantity': quantity})
                    
            elif data['type'] == 'remove_item':
                item_id = data['item_id']
                quantity = data['quantity']
                
                # Prevent game item duplication
                if any(item['id'] == item_id for item in inventories[player_id]):
                    inventories[player_id] = [item for item in inventories[player_id] if item['id'] != item_id]
                    
            elif data['type'] == 'trade':
                trader_id = data['trader_id']
                receiver_id = data['receiver_id']
                item_id = data['item_id']
                quantity = data['quantity']
                
                # Prevent game item duplication
                if any(item['id'] == item_id for item in inventories[player_id]):
                    if player_id != trader_id and player_id != receiver_id:
                        inventories[trader_id] = [item for item in inventories[trader_id] if item['id'] != item_id]
                        inventories[receiver_id].append({'id': item_id, 'quantity': quantity})
                        
            await websocket.send(json.dumps({'type': 'update', 'inventory': inventories[player_id]}))
            
        except ConnectionClosed:
            del inventories[player_id]

async def main():
    async with serve(handle_connection, "localhost", 8765):
        print("Server started on port 8765")
        await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())